      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mortgage Payoff Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate how extra mortgage payments can shorten your payoff time and reduce total interest.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Remaining balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current interest rate (%)</label><input type="number" step="0.1" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current monthly payment</label><input type="number" value={Math.round(payment)} onChange={(e) => setPayment(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Extra monthly payment</label><input type="number" value={extra} onChange={(e) => setExtra(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${balance}-${rate}-${payment}-${extra}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">New Payoff Time</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-payoff">{formatMonths(accelerated.months)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Interest Saved", money(interestSaved)], ["New Payoff Date", payoffDate], ["Months Saved", Number.isFinite(baseline.months) ? `${baseline.months - accelerated.months}` : "0"]].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-lg font-extrabold text-foreground">{value}</p></div>)}</div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How Extra Payments Help You Pay Off Your Mortgage Faster for Free</h2><p className="text-muted-foreground leading-relaxed">This early mortgage payoff calculator free applies extra payments directly to principal each month.</p>
          <h2 className="text-2xl font-bold text-foreground">How Much Interest Can You Save by Paying Extra</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Mortgage Payoff Comparison - $200,000 at 6% - 30yr</caption><thead className="bg-muted/60"><tr>{["Extra Monthly Payment", "Payoff Time", "Interest Saved", "Total Savings"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.amount} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{money(row.amount)}</td><td className="py-2.5 px-3">{formatMonths(row.result.months)}</td><td className="py-2.5 px-3 text-emerald-600 dark:text-emerald-400">{money(row.saved)}</td><td className="py-2.5 px-3">{money(row.saved)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Early Mortgage Payoff Tool for Homeowners</h2><p className="text-muted-foreground leading-relaxed">Use this mortgage interest savings calculator free to compare extra payment options before changing your payoff plan.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/mortgage-payoff-calculator" headingLevel="h3" />
      </main>
